operations.reducer:
if (action.input.title) state.title = action.input.title;
if (action.input.description) state.description = action.input.description;
if (action.input.kind) state.kind = action.input.kind;
if (action.input.expectedResolution) state.expectedResolution = action.input.expectedResolution;
if (action.input.assignee) state.assignee = action.input.assignee;

const idx = state.blocks.indexOf(action.input.pledgeId);
if (idx === -1) throw new PledgeNotLinkedError('Pledge is not linked to this dependency');
state.blocks.splice(idx, 1);

if (state.status === 'RESOLVED') throw new DependencyAlreadyResolvedError('Dependency is already resolved');
if (state.status === 'ABANDONED') throw new InvalidStatusTransitionError('Cannot resolve an abandoned dependency');
state.status = 'RESOLVED';

state.externalRef = {
  url: action.input.url ?? null,
  txHash: action.input.txHash ?? null,
  proposalId: action.input.proposalId ?? null,
};

operations.schema:
input SetExternalRefInput {
    url: URL
    txHash: String
    proposalId: String
}
